interface User {
  id: string;
  name: string;
}

// Automatically merges new properties
interface User {
  email: string;
}

const user: User = {
  id: "1",
  name: "Alex",
  email: "a@b.com"
};

type Status = "active" | "inactive" | "pending";

type Timestamps = {
  createdAt: Date;
  updatedAt: Date;
};

// Intersection
type UserWithTimeline = {
  id: string;
  status: Status;
} & Timestamps;

// Mapped Type transformation
type Nullable<T> = {
  [K in keyof T]: T[K] | null;
};

// ❌ Type predicates (x is T) return a boolean,
//    forcing nested conditional blocks to narrow
const user = users.find((u) => u.id === "123");

if (user) {
  const order = orders.find((o) => o.userId === user.id);
  if (order) {
    console.log(order.total); // pyramid of nesting
  }
}

// asserts value is T -> if it doesn't throw, the type is narrowed
function assertExists<T>(value: T | null | undefined): asserts value is T {
  if (value == null) throw new Error("Missing value");
}

const user = users.find((u) => u.id === "123");
assertExists(user); // user is now T for the rest of the scope

const order = orders.find((o) => o.userId === user.id);
assertExists(order);

// Flat, zero nesting
console.log(order.total);

interface Theme { primary: string; fontSize: number; }

// ❌ Annotation widens the literal
const theme: Theme = { primary: "blue", fontSize: 16 };
type PrimaryColor = typeof theme.primary; // string

interface Theme { primary: string; fontSize: number; }

// ❌ Literals preserved, but the `fontsize` typo is NOT caught
const theme = { primary: "blue", fontsize: 16 } as const;

interface Theme { primary: string; fontSize: number; }

// ✅ Structure validated, literals & readonly preserved
const theme = { primary: "blue", fontSize: 16 } as const satisfies Theme;
type PrimaryColor = typeof theme.primary; // "blue"
// A `fontsize` typo now errors: does not exist in type 'Theme'

