// ❌ The throw isn't in the signature — callers get no warning to handle it
function fetchUser(id: string): User {
  if (!id) throw new Error("Invalid ID");
  return { id, name: "Alex" };
}

const user = fetchUser(""); // compiles fine, throws at runtime

// ❌ `e` is `unknown` — no typed information about what failed
try {
  const user = fetchUser("");
} catch (e) {
  // e: unknown
}

type Result<T, E> =
  | { ok: true; value: T }
  | { ok: false; error: E };

function fetchUser(id: string): Result<User, string> {
  if (!id) return { ok: false, error: "Invalid ID" };
  return { ok: true, value: { id, name: "Alex" } };
}

const result = fetchUser("123");
if (result.ok) {
  console.log(result.value.name); // value only reachable after the check
} else {
  console.log(result.error); // typed error
}

// ❌ Any string, any payload — nothing is checked
class EventEmitter {
  private listeners: Record<string, Function[]> = {};
  on(event: string, cb: Function) {
    (this.listeners[event] ??= []).push(cb);
  }
  emit(event: string, data: any) {
    this.listeners[event]?.forEach((cb) => cb(data));
  }
}

const e = new EventEmitter();
e.emit("user:logn", { id: 1 });    // typo — silently ignored
e.emit("user:login", { name: 1 }); // wrong payload — unnoticed

interface EventMap {
  "user:login": { id: number; name: string };
  "user:logout": { id: number };
  "page:view": { url: string };
}

class EventEmitter<T extends Record<string, unknown>> {
  private listeners: { [K in keyof T]?: Array<(data: T[K]) => void> } = {};
  on<K extends keyof T>(event: K, cb: (data: T[K]) => void) {
    (this.listeners[event] ??= []).push(cb);
  }
  emit<K extends keyof T>(event: K, data: T[K]) {
    this.listeners[event]?.forEach((cb) => cb(data));
  }
}

const emitter = new EventEmitter<EventMap>();
emitter.emit("user:login", { id: 1, name: "tomek" }); // ✅
emitter.emit("user:logn", { id: 1 });    // ❌ not a known event
emitter.emit("user:login", { name: 1 }); // ❌ wrong payload

type Role = "admin" | "user";

// ❌ Distributes per member, so a mixed union yields a mixed result
type IsRole<T> = T extends Role ? "valid" : "invalid";

type Check = IsRole<"admin" | "guest">; // "valid" | "invalid"

type Role = "admin" | "user";

// ✅ Non-distributive: the union is checked as a single unit
type IsRole<T> = [T] extends [Role] ? "valid" : "invalid";

type Ok = IsRole<"admin" | "user">;  // "valid"
type No = IsRole<"admin" | "guest">; // "invalid"

type Order = { id: string; items: string[] };

function ship(order: Order) {
  /* ship logic */
}

// ❌ Nothing stops shipping an unvalidated order
ship({ id: "1", items: ["hat"] });

type Order<State> = { id: string; items: string[] } & {
  readonly __state: State;
};

type Unvalidated = Order<"unvalidated">;
type Validated = Order<"validated">;

function validate(order: Unvalidated): Validated {
  return { ...order, __state: "validated" };
}
function ship(order: Validated): void {
  /* ship logic */
}

const order: Unvalidated = { id: "1", items: ["hat"], __state: "unvalidated" };

ship(order);           // ❌ Validated expected, got Unvalidated
ship(validate(order)); // ✅ must validate first

// ❌ Literals widen to string / number…
function createConfig<T>(config: T) {
  return config;
}
const a = createConfig({ theme: "dark", port: 3000 });
// a: { theme: string; port: number }

// …so every caller has to opt back in:
const b = createConfig({ theme: "dark", port: 3000 } as const);

// ✅ `const T` infers deeply readonly, literal types with no caller syntax
function createConfig<const T>(config: T) {
  return config;
}

const c = createConfig({ theme: "dark", port: 3000 });
// c: { readonly theme: "dark"; readonly port: 3000 }
